                    const nextPos = bot.path.shift();
                    bot.x = nextPos.x;
                    bot.y = nextPos.y;
                    if (bot.x === maze.exit.x && bot.y === maze.exit.y) {
                        bot.completed = true;
                    }
                }
            });
        }

        // Update exposed properties for API consistency
        this.bots = bots.map(b => ({ x: b.x, y: b.y }));
        this.completed = bots.filter(b => b.completed).length;
        this.elapsedMs = Math.floor(performance.now() - startTime);
    },

    reset() {
        initGame();
        // Force a redraw immediately
        const now = performance.now();
        lastTickTime = now;
        requestAnimationFrame(loop);
    }
};

// Event Listeners
resetBtn.addEventListener('click', () => {
    window.game.reset();
});

// Start
initGame();
requestAnimationFrame(loop);

</script>
